289→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
290→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
291→{
292→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
293→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
294→
295→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
296→	{
297→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
298→		return false;
299→	}
300→
301→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
302→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
303→
304→	// 验证两个源单位 TypeID 相同
305→	if (UnitA.TypeID != UnitB.TypeID)
306→	{
307→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
308→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
309→		return false;
310→	}
311→
312→	// 验证 TargetTypeID 在进化目标列表中
313→	if (!UnitRegistry)
314→	{
315→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
316→		return false;
317→	}
318→
319→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
320→	if (!Targets.Contains(TargetTypeID))
321→	{
322→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
323→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
324→		return false;
325→	}
326→
327→	// 创建进化后的新单位
328→	FLFPUnitEntry NewUnit;
329→	NewUnit.TypeID = TargetTypeID;
330→	NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
331→
332→	// 移除两个源单位（同一数组时先移除大索引避免偏移）
333→	if (bSourceAIsParty == bSourceBIsParty)
334→	{
