389→void ALFPTacticsUnit::Tick(float DeltaTime)
390→{
391→    Super::Tick(DeltaTime);
392→
393→    // 逐格平滑移动
394→    if (bIsMoving && CurrentPathIndex >= 0 && CurrentPathIndex < MovePath.Num() - 1)
395→    {
396→        MoveProgress += MoveSpeed * DeltaTime;
397→
398→        ALFPHexTile* FromTile = MovePath[CurrentPathIndex];
399→        ALFPHexTile* ToTile = MovePath[CurrentPathIndex + 1];
400→
401→        if (FromTile && ToTile)
402→        {
403→            FVector StartPos = FromTile->GetActorLocation() + FVector(0, 0, 1);
404→            FVector EndPos = ToTile->GetActorLocation() + FVector(0, 0, 1);
405→
406→            float Alpha = FMath::Clamp(MoveProgress, 0.f, 1.f);
407→            SetActorLocation(FMath::Lerp(StartPos, EndPos, Alpha));
408→        }
409→
410→        if (MoveProgress >= 1.0f)
411→        {
412→            CurrentPathIndex++;
413→            MoveProgress = 0.0f;
414→
415→            if (CurrentPathIndex >= MovePath.Num() - 1)
416→            {
417→                // 到达终点
418→                FinishMove();
419→            }
420→        }

420→        }
421→    }
422→}
