506→void ALFPTacticsUnit::ApplyDamageToTarget(ALFPTacticsUnit* Target)
507→{
508→    if (!Target || Target->bIsDead) return;
509→
510→    // 基础伤害计算
511→    int32 Damage = AttackPower;
512→
513→    // 伤害随机浮动（10% 范围）
514→    float RandomFactor = FMath::RandRange(0.9f, 1.1f);
515→    Damage = FMath::RoundToInt(Damage * RandomFactor);
516→
517→    // 应用伤害
518→    Target->TakeDamage(Damage);
519→
520→    // 消耗行动力
521→    ConsumeMovePoints(1);
