736→TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
737→{
738→    TArray<ALFPHexTile*> AttackRangeTiles;
739→
740→    if (ALFPHexGridManager* GridManager = GetGridManager())
741→    {
742→        // 近战攻击范围
743→        if (bMeleeAttack)
744→        {
745→            // 获取相邻格子
746→            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
747→            for (const FLFPHexCoordinates& Coord : Neighbors)
748→            {
749→                FLFPHexCoordinates Key(Coord.Q, Coord.R);
750→                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
751→                {
752→                    AttackRangeTiles.Add(Tile);
753→                }
754→            }
755→        }
756→        // 远程攻击范围
757→        else
758→        {
759→            // 获取攻击范围内的所有格子
760→            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
761→
762→            for (ALFPHexTile* Tile : TilesInRange)
763→            {
764→                AttackRangeTiles.Add(Tile);
765→            }
766→        }
767→    }
768→
769→    return AttackRangeTiles;
770→}
