1061→        PickupDeployedUnit(DeployedUnits[PartyIndex]);
1062→    }
1063→
1064→    const FLFPUnitEntry& Entry = GI->PartyUnits[PartyIndex];
1065→    TSubclassOf<ALFPTacticsUnit> UnitClass = GI->UnitRegistry->GetUnitClass(Entry.TypeID);
1066→    if (!UnitClass) return;
1067→
1068→    // 在鼠标位置生成预览单位
1069→    FVector UnitSpawnLoc = FVector(0, 0, 50.f);
1070→    FActorSpawnParameters SpawnParams;
1071→    SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
1072→    PlacingUnitPreview = GetWorld()->SpawnActor<ALFPTacticsUnit>(UnitClass, UnitSpawnLoc, FRotator::ZeroRotator, SpawnParams);
1073→
1074→    if (PlacingUnitPreview)
1075→    {
1076→        PlacingUnitPreview->Affiliation = EUnitAffiliation::UA_Player;
1077→        PlacingUnitPreview->UnitTypeID = Entry.TypeID;
1078→        PlacingUnitPreview->UnitTier = Entry.Tier;
1079→        GI->ApplyOwnedRelicsToUnit(PlacingUnitPreview);
1080→    }
1081→
1082→    PlacingPartyIndex = PartyIndex;
1083→    bIsPlacingUnit = true;
1084→
1085→    if (DeploymentWidget)
1086→    {
1087→        DeploymentWidget->MarkUnitSelecting(PartyIndex);
1088→    }
1089→
1090→    UE_LOG(LogTemp, Log, TEXT("开始放置单位 %s（索引 %d）"), *Entry.TypeID.ToString(), PartyIndex);
1091→}
1092→
1093→void ALFPTacticsPlayerController::PlaceUnit(ALFPHexTile* Tile)
1094→{
1095→    if (!Tile || !PlacingUnitPreview || PlacingPartyIndex < 0) return;
1096→
1097→    // 放置到格子上
1098→    FVector TileLocation = Tile->GetActorLocation() + FVector(0, 0, 50.f);
1099→    PlacingUnitPreview->SetActorLocation(TileLocation);
1100→    PlacingUnitPreview->SetCurrentCoordinates(Tile->GetCoordinates());
1101→
1102→    // 更新格子占用
1103→    Tile->SetIsOccupied(true);
1104→    Tile->SetUnitOnTile(PlacingUnitPreview);
1105→
1106→    // 记录到已布置列表
1107→    if (DeployedUnits.IsValidIndex(PlacingPartyIndex))
1108→    {
1109→        DeployedUnits[PlacingPartyIndex] = PlacingUnitPreview;
1110→    }
1111→
1112→    // 更新 UI
1113→    if (DeploymentWidget)
1114→    {
1115→        DeploymentWidget->MarkUnitPlaced(PlacingPartyIndex, true);
1116→    }
1117→
1118→    UE_LOG(LogTemp, Log, TEXT("放置单位到格子 (%d, %d)"), Tile->GetCoordinates().Q, Tile->GetCoordinates().R);
1119→
1120→    // 重置放置状态
1121→    PlacingUnitPreview = nullptr;
1122→    PlacingPartyIndex = -1;
1123→    bIsPlacingUnit = false;
1124→}
1125→
1126→void ALFPTacticsPlayerController::CancelPlacing()
1127→{
1128→    if (PlacingUnitPreview)
1129→    {
1130→        PlacingUnitPreview->Destroy();
1131→        PlacingUnitPreview = nullptr;
1132→    }
1133→
1134→    PlacingPartyIndex = -1;
1135→    bIsPlacingUnit = false;
1136→}
1137→
1138→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1139→{
1140→    if (!Unit) return;
1141→
1142→    // 找到对应的 PartyIndex
1143→    int32 FoundIndex = DeployedUnits.Find(Unit);
1144→    if (FoundIndex == INDEX_NONE) return;
1145→
1146→    // 清除格子占用
1147→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1148→    if (OldTile)
1149→    {
1150→        OldTile->SetIsOccupied(false);
1151→        OldTile->SetUnitOnTile(nullptr);
1152→    }
1153→
1154→    // 设置为跟随鼠标的预览
1155→    PlacingUnitPreview = Unit;
1156→    PlacingPartyIndex = FoundIndex;
1157→    bIsPlacingUnit = true;
1158→
1159→    // 清除已布置记录
1160→    DeployedUnits[FoundIndex] = nullptr;
1161→
1162→    // 更新 UI
1163→    if (DeploymentWidget)
1164→    {
1165→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1166→    }
1167→
1168→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
1169→}
1170→
1171→void ALFPTacticsPlayerController::ConfirmDeployment()
1172→{
1173→    if (!bIsInDeployment) return;
1174→
1175→    // 取消高亮
1176→    // 清除出生点高亮
1177→    GridManager->ClearAllHighlights();
1178→    PlayerSpawnTiles.Empty();
1179→
1180→    // 移除布置 UI
1181→    if (DeploymentWidget)
1182→    {
1183→        DeploymentWidget->OnUnitSelected.RemoveDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1184→        DeploymentWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1185→        DeploymentWidget->RemoveFromParent();
1186→    }
1187→
1188→    bIsInDeployment = false;
1189→    bIsPlacingUnit = false;
1190→
1191→    // 通知 TurnManager 结束布置阶段
1192→    ALFPTurnManager* TurnManager = GetTurnManager();
1193→    if (TurnManager)
1194→    {
1195→        TurnManager->EndDeploymentPhase();
1196→    }
1197→
1198→    UE_LOG(LogTemp, Log, TEXT("布置确认，进入战斗"));
1199→}
