 19→void ULFPHealthBarWidget::BindToUnit(ALFPTacticsUnit* Unit)
 20→{
 21→	if (!Unit || BoundUnit == Unit) return;
 22→
 23→	// 解绑旧单位
 24→	UnbindFromUnit();
 25→
 26→	// 绑定新单位
 27→	BoundUnit = Unit;
 28→
 29→	// 订阅事件
 30→	BoundUnit->OnHealthChangedDelegate.AddDynamic(this, &ULFPHealthBarWidget::OnHealthChanged);
 31→	BoundUnit->OnDeathDelegate.AddDynamic(this, &ULFPHealthBarWidget::OnUnitDeath);
 32→
 33→	// 初始化数据
 34→	UpdateHealthBar(BoundUnit->GetCurrentHealth(), BoundUnit->GetMaxHealth());
 35→
 36→	// 显示血条
 37→	SetVisibility(ESlateVisibility::Visible);
 38→
 39→	// 更新阵营颜色
 40→	if (BoundUnit)
 41→	{
 42→		UpdateAffiliationColor(BoundUnit->GetAffiliation());
 43→	}
 44→}
