 46→void ULFPHealthBarWidget::UnbindFromUnit()
 47→{
 48→	if (BoundUnit)
 49→	{
 50→		// 取消订阅事件
 51→		BoundUnit->OnHealthChangedDelegate.RemoveDynamic(this, &ULFPHealthBarWidget::OnHealthChanged);
 52→		BoundUnit->OnDeathDelegate.RemoveDynamic(this, &ULFPHealthBarWidget::OnUnitDeath);
 53→		BoundUnit = nullptr;
 54→	}
 55→
 56→	// 隐藏血条
 57→	SetVisibility(ESlateVisibility::Hidden);
 58→}
