 60→void ULFPHealthBarWidget::UpdateHealthBar(int32 CurrentHealth, int32 MaxHealth)
 61→{
 62→	if (!HealthProgressBar || !HealthText) return;
 63→
 64→	// 计算血量百分比
 65→	float HealthPercent = (MaxHealth > 0) ? (float)CurrentHealth / MaxHealth : 0.0f;
 66→
 67→	// 更新进度条
 68→	HealthProgressBar->SetPercent(HealthPercent);
 69→
 70→	// 更新文本
 71→	FString HealthString = FString::Printf(TEXT("%d / %d"), CurrentHealth, MaxHealth);
 72→	HealthText->SetText(FText::FromString(HealthString));
 73→}
