116→void ALFPTurnManager::EndCurrentRound()
117→{
118→    if (bBattleEnded) return;
119→
120→    bIsInRound = false;
121→
122→    SetPhase(EBattlePhase::BP_RoundEnd);
123→
124→    // 通知玩家本回合结束
125→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
126→    {
127→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
128→        {
129→            PC->OnRoundEnded(CurrentRound);
130→        }
131→    }
132→
133→    // 添加延迟后开始新回合
134→    FTimerHandle TimerHandle;
135→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
136→}
