183→bool ALFPTacticsUnit::MoveToTile(ALFPHexTile* NewTargetTile)
184→{
185→    if (!NewTargetTile || !HasEnoughMovePoints(1)) return false;
186→
187→    ALFPHexGridManager* GridManager = GetGridManager();
188→    if (!GridManager) return false;
189→
190→    // 获取当前所在的格子
191→    ALFPHexTile* CurrentTile = GridManager->GetTileAtCoordinates(CurrentCoordinates);
192→    if (!CurrentTile) return false;
193→
194→    // 寻找路径（FindPath 返回的路径不包含起点）
195→    MovePath = GridManager->FindPath(CurrentTile, NewTargetTile);
196→    // 计算路径实际移动代价（考虑地形）
197→    int32 PathCost = 0;
198→    for (ALFPHexTile* Tile : MovePath)
199→    {
200→        PathCost += Tile->GetMovementCost();
201→    }
202→    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
203→
204→    // 在路径开头插入当前格子，使 Tick 中 MovePath[0] → MovePath[1] 为第一段移动
205→    MovePath.Insert(CurrentTile, 0);
206→
207→    // 设置移动状态
208→    CurrentTile->SetIsOccupied(false);
209→    TargetTile = NewTargetTile;
210→    CurrentPathIndex = 0;
211→    MoveProgress = 0.0f;
212→    MovementRangeTiles.Empty();
213→
214→    // 启动移动动画（Tick 驱动逐格插值）
215→    bIsMoving = true;
216→
217→    return true;
218→}
