 25→void ALFPTurnManager::StartGame()
 26→{
 27→    // 收集场上所有单位（敌方预放置在关卡中）
 28→    TArray<AActor*> FoundActors;
 29→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 30→
 31→    for (AActor* Actor : FoundActors)
 32→    {
 33→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 34→        {
 35→            // 仅注册非玩家单位（玩家单位在布置阶段结束后注册）
 36→            if (Unit->GetAffiliation() != EUnitAffiliation::UA_Player)
 37→            {
 38→                TurnOrderUnits.Add(Unit);
 39→            }
 40→        }
 41→    }
 42→
 43→    // 初始化阵营 AP
 44→    FactionCurrentAP.Add(EUnitAffiliation::UA_Player, FactionInitialAP);
 45→    FactionCurrentAP.Add(EUnitAffiliation::UA_Enemy, FactionInitialAP);
 46→    FactionCurrentAP.Add(EUnitAffiliation::UA_Neutral, FactionInitialAP);
 47→
 48→    // 标记为布置阶段（不广播，等 PlayerController 绑定委托后主动调用）
 49→    CurrentPhase = EBattlePhase::BP_Deployment;
 50→}
