157→void ALFPTurnManager::BeginEnemyPlanningPhase()
158→{
159→    SetPhase(EBattlePhase::BP_EnemyPlanning);
160→
161→    // 过滤出存活的敌方单位，按速度排序
162→    PlanningOrderEnemies.Empty();
163→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
164→    {
165→        if (Unit && Unit->IsAlive() && Unit->IsEnemy())
166→        {
167→            PlanningOrderEnemies.Add(Unit);
168→        }
169→    }
170→
171→    // 敌方单位已按速度排序（继承自 TurnOrderUnits 的排序）
172→
173→    CurrentPlanningEnemyIndex = 0;
174→
175→    if (PlanningOrderEnemies.Num() == 0)
176→    {
177→        // 没有敌方单位，直接进入行动阶段
178→        EndEnemyPlanningPhase();
179→        return;
180→    }
181→
182→    // 隐藏玩家技能选择UI
183→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
184→    {
185→        PC->HideSkillSelection();
186→    }
187→
188→    // Step 1: 全局技能分配（按优先级分配AP技能）
189→    AllocateEnemySkills();
190→
191→    // Step 2: 按速度顺序移动展示
192→    ProcessNextEnemyPlan();
193→}
