 16→void ULFPDeploymentWidget::Setup(const TArray<FLFPUnitEntry>& PartyUnits, ULFPUnitRegistryDataAsset* Registry)
 17→{
 18→	CachedPartyUnits = PartyUnits;
 19→	UnitRegistry = Registry;
 20→
 21→	// 初始化放置状态
 22→	PlacedStates.Empty();
 23→	PlacedStates.SetNum(3);
 24→	for (int32 i = 0; i < 3; i++)
 25→	{
 26→		PlacedStates[i] = false;
 27→	}
 28→
 29→	bConfirmEnabled = false;
 30→
 31→	// 设置各槽位图标和可见性
 32→	for (int32 i = 0; i < 3; i++)
 33→	{
 34→		UButton* Btn = GetUnitButton(i);
 35→		UImage* Img = GetUnitImage(i);
 36→
 37→		if (i < PartyUnits.Num() && PartyUnits[i].IsValid() && Registry)
 38→		{
 39→			// 有单位：显示按钮，设置图标
 40→			if (Btn) Btn->SetVisibility(ESlateVisibility::Visible);
 41→
 42→			FLFPUnitRegistryEntry Entry;
 43→			if (Img && Registry->FindEntry(PartyUnits[i].TypeID, Entry) && Entry.Icon)
 44→			{
 45→				Img->SetBrushFromTexture(Entry.Icon);
 46→				Img->SetVisibility(ESlateVisibility::Visible);
 47→			}
 48→		}
 49→		else
 50→		{
 51→			// 无单位：隐藏按钮
 52→			if (Btn) Btn->SetVisibility(ESlateVisibility::Collapsed);
 53→		}
 54→	}
 55→
