225→void ALFPTacticsUnit::FinishMove()
226→{
227→    bIsMoving = false;
228→
229→    // 更新到目标位置
230→    if (TargetTile)
231→    {
232→        SetCurrentCoordinates(TargetTile->GetCoordinates());
233→        // 计算路径实际移动代价（跳过 MovePath[0] 即起点格子）
234→        int32 TotalCost = 0;
235→        for (int32 i = 1; i < MovePath.Num(); i++)
236→        {
237→            TotalCost += MovePath[i]->GetMovementCost();
238→        }
239→        ConsumeMovePoints(TotalCost);
240→    }
241→
242→    // 清除移动状态
243→    TargetTile = nullptr;
244→    MovePath.Empty();
245→    CurrentPathIndex = -1;
246→    MoveProgress = 0.0f;
247→
248→    // 广播移动完成
249→    OnMoveFinished.Broadcast();
250→}
