388→void ALFPTacticsUnit::Tick(float DeltaTime)
389→{
390→    Super::Tick(DeltaTime);
391→
392→    // 逐格平滑移动
393→    if (bIsMoving && CurrentPathIndex >= 0 && CurrentPathIndex < MovePath.Num() - 1)
394→    {
395→        MoveProgress += MoveSpeed * DeltaTime;
396→
397→        ALFPHexTile* FromTile = MovePath[CurrentPathIndex];
398→        ALFPHexTile* ToTile = MovePath[CurrentPathIndex + 1];
399→
400→        if (FromTile && ToTile)
401→        {
402→            FVector StartPos = FromTile->GetActorLocation() + FVector(0, 0, 1);
403→            FVector EndPos = ToTile->GetActorLocation() + FVector(0, 0, 1);
404→
405→            float Alpha = FMath::Clamp(MoveProgress, 0.f, 1.f);
406→            SetActorLocation(FMath::Lerp(StartPos, EndPos, Alpha));
407→        }
408→
409→        if (MoveProgress >= 1.0f)
410→        {
411→            CurrentPathIndex++;
412→            MoveProgress = 0.0f;
413→
414→            if (CurrentPathIndex >= MovePath.Num() - 1)
415→            {
416→                // 到达终点
417→                FinishMove();
418→            }
419→        }
420→    }
421→}
