735→TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
736→{
737→    TArray<ALFPHexTile*> AttackRangeTiles;
738→
739→    if (ALFPHexGridManager* GridManager = GetGridManager())
740→    {
741→        // 近战攻击范围
742→        if (bMeleeAttack)
743→        {
744→            // 获取相邻格子
745→            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
746→            for (const FLFPHexCoordinates& Coord : Neighbors)
747→            {
748→                FLFPHexCoordinates Key(Coord.Q, Coord.R);
749→                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
750→                {
751→                    AttackRangeTiles.Add(Tile);
752→                }
753→            }
754→        }
755→        // 远程攻击范围
756→        else
757→        {
758→            // 获取攻击范围内的所有格子
759→            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
760→
761→            for (ALFPHexTile* Tile : TilesInRange)
762→            {
763→                AttackRangeTiles.Add(Tile);
764→            }
765→        }
766→    }
767→
768→    return AttackRangeTiles;
769→}
