771→bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
772→{
773→    if (!Target || !Target->GetCurrentTile()) return false;
774→
775→    // 计算距离
776→    int32 Distance = FLFPHexCoordinates::Distance(
777→        CurrentCoordinates,
778→        Target->GetCurrentCoordinates()
779→    );
780→
781→    // 近战攻击判定
782→    if (bMeleeAttack)
783→    {
784→        return Distance == 1; // 相邻格子
785→    }
786→    // 远程攻击判定
787→    else
788→    {
789→        return Distance >= 2 && Distance <= AttackRange;
790→    }
