209→
210→		for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
211→		{
212→			switch (Effect.EffectType)
213→			{
214→			case ELFPRelicEffectType::RET_MaxHealthFlat:
215→				Unit->MaxHealth += Effect.Value;
216→				break;
217→			case ELFPRelicEffectType::RET_AttackFlat:
218→				Unit->AttackPower += Effect.Value;
219→				break;
220→			case ELFPRelicEffectType::RET_DefenseFlat:
221→				Unit->Defense += Effect.Value;
222→				break;
223→			case ELFPRelicEffectType::RET_SpeedFlat:
224→				Unit->Speed += Effect.Value;
225→				break;
226→			default:
227→				break;
228→			}
229→		}
230→	}
231→
232→	Unit->MaxHealth = FMath::Max(Unit->MaxHealth, 1);
233→	Unit->CurrentHealth = Unit->MaxHealth;
