101→ALFPTacticsUnit* ALFPAIController::FindBestSkillTarget(ULFPSkillBase* Skill) const
102→{
103→    if (!ControlledUnit || !Skill) return nullptr;
104→
105→    TArray<AActor*> AllUnits;
106→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), AllUnits);
107→
108→    ALFPTacticsUnit* BestTarget = nullptr;
109→    float BestHatred = -MAX_FLT;
110→
111→    for (AActor* Actor : AllUnits)
112→    {
113→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
114→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
115→        {
116→            float Hatred = Skill->CalculateHatredValue(ControlledUnit, Unit);
117→            if (Hatred > BestHatred)
118→            {
119→                BestHatred = Hatred;
120→                BestTarget = Unit;
121→            }
122→        }
123→    }
124→
125→    return BestTarget;
