303→ULFPSkillBase* ALFPAIController::SelectBestSkill()
304→{
305→    if (!ControlledUnit) return nullptr;
306→
307→    TArray<ULFPSkillBase*> Skills = ControlledUnit->GetAvailableSkills();
308→    ULFPSkillBase* BestSkill = nullptr;
309→    float BestScore = -MAX_FLT;
310→
311→    for (ULFPSkillBase* Skill : Skills)
312→    {
313→        if (!Skill) continue;
314→
315→        // 轻量检查：冷却和行动点
316→        if (!Skill->IsAvailable()) continue;
317→
318→        // 找该技能的最佳目标
319→        ALFPTacticsUnit* PotentialTarget = FindBestSkillTarget(Skill);
320→        if (!PotentialTarget) continue;
321→
322→        // 检查是否存在可达的施法位置
323→        ALFPHexTile* PotentialTargetTile = PotentialTarget->GetCurrentTile();
324→        if (!PotentialTargetTile) continue;
325→
326→        ALFPHexTile* CasterPos = FindBestCasterPosition(Skill, PotentialTargetTile);
327→        if (!CasterPos) continue;
328→
329→        // 评分：仇恨值作为基础分
330→        float Score = Skill->CalculateHatredValue(ControlledUnit, PotentialTarget);
331→
332→        // 非默认攻击技能额外加分（鼓励使用特殊技能）
333→        if (!Skill->bIsDefaultAttack)
334→        {
335→            Score *= 1.5f;
336→        }
337→
338→        if (Score > BestScore)
339→        {
340→            BestScore = Score;
341→            BestSkill = Skill;
342→        }
343→    }
344→
345→    // Fallback 到默认攻击
346→    if (!BestSkill)
347→    {
348→        BestSkill = ControlledUnit->GetDefaultAttackSkill();
349→    }
350→
351→    return BestSkill;
352→}
