354→ALFPHexTile* ALFPAIController::FindBestCasterPosition(ULFPSkillBase* Skill, ALFPHexTile* TargetTile)
355→{
356→    if (!ControlledUnit || !Skill || !TargetTile || !GridManager) return nullptr;
357→
358→    // 获取移动范围内的所有格子
359→    ALFPHexTile* CurrentTile = ControlledUnit->GetCurrentTile();
360→    TArray<ALFPHexTile*> MovementRange = GridManager->GetTilesInRange(
361→        CurrentTile,
362→        ControlledUnit->GetCurrentMovePoints()
363→    );
364→
365→    // 也包含当前格子（可能不需要移动）
366→    MovementRange.AddUnique(CurrentTile);
367→
368→    ALFPHexTile* BestTile = nullptr;
369→    float BestValue = -MAX_FLT;
370→
371→    for (ALFPHexTile* Tile : MovementRange)
372→    {
373→        if (!Tile) continue;
374→
375→        // 跳过被其他单位占据的格子（但允许自己当前所在格）
376→        ALFPTacticsUnit* Occupant = Tile->GetUnitOnTile();
377→        if (Occupant && Occupant != ControlledUnit) continue;
378→
379→        // 位置检查：从该格子能否对目标格子释放技能
380→        if (!Skill->CanReleaseFrom(Tile, TargetTile)) continue;
381→
382→        // 评估位置价值
383→        float Value = 0.0f;
384→
385→        int32 DistToTarget = FLFPHexCoordinates::Distance(
386→            Tile->GetCoordinates(),
387→            TargetTile->GetCoordinates()
388→        );
389→
390→        // 在技能范围内加分
391→        Value += 30.0f;
392→
393→        // 离目标越近越好（在范围内的前提下）
394→        //Value += 10.0f / FMath::Max(DistToTarget, 1);
395→
396→        // 离当前位置越近越好（减少移动消耗）
397→        int32 MoveDistance = FLFPHexCoordinates::Distance(
398→            CurrentTile->GetCoordinates(),
399→            Tile->GetCoordinates()
400→        );
401→        Value -= MoveDistance * 2.0f;
402→
403→        if (Value > BestValue)
404→        {
405→            BestValue = Value;
406→            BestTile = Tile;
407→        }
408→    }
409→
410→    return BestTile;
411→}
