155→float ALFPAIController::CalculateThreatValue(ALFPTacticsUnit* Target) const
156→{
157→    if (!ControlledUnit || !Target) return 0.0f;
158→
159→    // 威胁值 = 目标攻击力 * (1 - 目标当前血量/最大血量)
160→    float ThreatValue = Target->GetAttackPower() * (1.0f - (float)Target->GetCurrentHealth() / Target->GetMaxHealth());
161→
162→    // 距离因素（越近威胁越大）
163→    int32 Distance = FLFPHexCoordinates::Distance(
164→        ControlledUnit->GetCurrentCoordinates(),
165→        Target->GetCurrentCoordinates()
166→    );
167→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
168→
169→    // 应用行为数据
170→    if (BehaviorData)
171→    {
172→        if (BehaviorData->bPrioritizeWeakTargets)
173→        {
174→            // 增加对低血量目标的权重
175→            float HealthRatio = (float)Target->GetCurrentHealth() / Target->GetMaxHealth();
176→            ThreatValue *= (2.0f - HealthRatio); // 血量越低，威胁值越高
177→        }
178→
179→        // 应用攻击性系数
180→        ThreatValue *= BehaviorData->Aggressiveness;
181→    }
182→
183→    return ThreatValue * DistanceFactor;
184→}
185→
186→float ALFPAIController::CalculatePositionValue(ALFPHexTile* Tile, ALFPTacticsUnit* Target) const
187→{
188→    if (!Tile || !Target) return 0.0f;
189→
190→    float PositionValue = 0.0f;
191→
192→    // 1. 离目标越近越好
193→    int32 DistanceToTarget = FLFPHexCoordinates::Distance(
194→        Tile->GetCoordinates(),
195→        Target->GetCurrentCoordinates()
196→    );
197→    PositionValue += 10.0f / FMath::Max(DistanceToTarget, 1);
198→
199→    // 2. 如果在攻击范围内额外加分
200→    if (DistanceToTarget <= ControlledUnit->GetAttackRange())
201→    {
202→        PositionValue += 20.0f;
203→    }
204→
205→    // 3. 靠近其他敌方单位（团队协作加分）
206→    TArray<AActor*> EnemyUnits;
207→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), EnemyUnits);
208→
209→    for (AActor* Actor : EnemyUnits)
210→    {
211→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
212→        if (Unit && Unit != ControlledUnit && Unit->IsEnemy() && Unit->IsAlive())
213→        {
214→            int32 DistanceToAlly = FLFPHexCoordinates::Distance(
215→                Tile->GetCoordinates(),
216→                Unit->GetCurrentCoordinates()
217→            );
218→
219→            if (DistanceToAlly <= 2)
220→            {
221→                PositionValue += 5.0f / FMath::Max(DistanceToAlly, 1);
222→            }
223→        }
224→    }
225→
226→    return PositionValue;
227→}
