229→// ==== 规划阶段方法 ====
230→
231→FEnemyActionPlan ALFPAIController::CreateActionPlan(ULFPSkillBase* PreAllocatedSkill)
232→{
233→    FEnemyActionPlan Plan;
234→    Plan.EnemyUnit = ControlledUnit;
235→
236→    if (!ControlledUnit || !GridManager)
237→    {
238→        return Plan;
239→    }
240→
241→    // 1. 选择技能：优先使用预分配的，否则自行选择（会 fallback 到默认攻击）
242→    ULFPSkillBase* ChosenSkill = PreAllocatedSkill ? PreAllocatedSkill : SelectBestSkill();
243→    if (!ChosenSkill)
244→    {
245→        return Plan;
246→    }
247→    Plan.PlannedSkill = ChosenSkill;
248→
249→    // 2. 根据技能的仇恨值选择目标
250→    ALFPTacticsUnit* Target = FindBestSkillTarget(ChosenSkill);
251→    if (!Target)
252→    {
253→        return Plan;
254→    }
255→    Plan.TargetUnit = Target;
256→
257→    // 3. 目标格子 = 目标单位当前所在格子
258→    ALFPHexTile* TargetTile = Target->GetCurrentTile();
259→    if (!TargetTile)
260→    {
261→        return Plan;
262→    }
263→    Plan.TargetTile = TargetTile;
264→
265→    // 4. 寻找最佳施法站位
266→    ALFPHexTile* CasterPos = FindBestCasterPosition(ChosenSkill, TargetTile);
267→    if (!CasterPos)
268→    {
269→        // 找不到合适的施法位置，尝试原地
270→        CasterPos = ControlledUnit->GetCurrentTile();
271→    }
272→    Plan.CasterPositionTile = CasterPos;
273→
274→    // 5. 移动到施法位置
275→    if (CasterPos && CasterPos != ControlledUnit->GetCurrentTile())
276→    {
277→        ControlledUnit->MoveToTile(CasterPos);
278→    }
279→
280→    // 6. 计算技能生效范围（EffectRangeCoords 相对于目标格子偏移）
281→    FLFPHexCoordinates TargetCoords = TargetTile->GetCoordinates();
282→    for (const FLFPHexCoordinates& Offset : ChosenSkill->EffectRangeCoords)
283→    {
284→        FLFPHexCoordinates AbsCoord(
285→            TargetCoords.Q + Offset.Q,
286→            TargetCoords.R + Offset.R
287→        );
288→        if (ALFPHexTile* EffectTile = GridManager->GetTileAtCoordinates(AbsCoord))
289→        {
290→            Plan.EffectAreaTiles.Add(EffectTile);
291→        }
292→    }
293→
294→    // 如果没有定义 EffectRangeCoords，至少包含目标格子本身
295→    if (Plan.EffectAreaTiles.Num() == 0)
296→    {
297→        Plan.EffectAreaTiles.Add(TargetTile);
298→    }
299→
300→    Plan.bIsValid = true;
301→    return Plan;
302→}
