325→void ALFPTurnManager::BeginUnitTurn(ALFPTacticsUnit* Unit)
326→{
327→    if (bBattleEnded) return;
328→
329→    OnTurnChanged.Broadcast();
330→
331→    CurrentUnit = Unit;
332→
333→    ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>();
334→
335→    // 敌方单位在行动阶段：执行预定计划
336→    if (Unit->IsEnemy() && CurrentPhase == EBattlePhase::BP_ActionPhase)
337→    {
338→        if (PC)
339→        {
340→            PC->HideSkillSelection();
341→        }
342→
343→        Unit->OnTurnStarted();
344→
345→        ExecuteEnemyPlan(Unit);
346→        return;
347→    }
348→
349→    // 玩家单位：保持原有逻辑
350→    if (Unit)
351→    {
352→        Unit->OnTurnStarted();
353→    }
354→
355→    if (PC)
356→    {
357→        PC->OnTurnStarted(Unit);
358→        PC->SelectUnit(Unit);
359→        PC->HandleSkillSelection();
360→    }
361→}
