363→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
364→{
365→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
366→
367→    if (Plan.bIsValid && Plan.PlannedSkill)
368→    {
369→        // 在原定目标格子释放技能（即使目标已死亡）
370→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
371→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
372→    }
373→
374→    // 清除头顶技能图标
375→    Unit->ClearActionPlan();
376→
377→    // 短延时后结束回合（让玩家看到技能效果）
378→    FTimerHandle TimerHandle;
379→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
380→    {
381→        Unit->SetHasActed(true);
382→        PassTurn();
383→    }, 0.5f, false);
384→}
