438→void ALFPTacticsUnit::TakeDamage(int32 Damage)
439→{
440→    if (bIsDead) return;
441→
442→	// 计算实际伤害（考虑防御）
443→	int32 ActualDamage = FMath::Max(Damage - Defense, 1);
444→	int32 OldHealth = CurrentHealth;
445→	CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
446→
447→	// 广播血量变化事件
448→	OnHealthChangedDelegate.Broadcast(CurrentHealth, MaxHealth);
449→
450→	// 蓝图事件
451→	OnTakeDamage(ActualDamage);
452→
453→	// 检查死亡
454→	if (CurrentHealth <= 0)
455→	{
456→		HandleDeath();
457→	}
458→}
