671→    //        // 血量越低，威胁值越高
672→    //    }
673→
674→    //    // 应用攻击性系数
675→    //    ThreatValue *= BehaviorData->Aggressiveness;
676→    //}
677→
678→    return ThreatValue * DistanceFactor;
