772→bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
773→{
774→    if (!Target || !Target->GetCurrentTile()) return false;
775→
776→    // 计算距离
777→    int32 Distance = FLFPHexCoordinates::Distance(
778→        CurrentCoordinates,
779→        Target->GetCurrentCoordinates()
780→    );
781→
782→    // 近战攻击判定
783→    if (bMeleeAttack)
784→    {
785→        return Distance == 1; // 相邻格子
786→    }
787→    // 远程攻击判定
788→    else
789→    {
790→        return Distance >= 2 && Distance <= AttackRange;
791→    }
792→}
