 488→void ALFPTacticsPlayerController::OnCameraPan(const FInputActionValue& Value)
 489→{
 490→    // 获取输入值（WASD/方向键）
 491→    const FVector2D PanValue = Value.Get<FVector2D>();
 492→
 493→    // 计算移动方向（基于当前相机旋转）
 494→    FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
 495→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
 496→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
 497→
 498→    // 计算移动偏移
 499→    FVector PanDirection = (Forward * PanValue.Y) + (Right * PanValue.X);
 500→    PanDirection.Z = 0;
 501→    PanDirection.Normalize();
 502→
 503→    // 应用移动
 504→    CameraOffset += PanDirection * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
 505→}
