 625→void ALFPTacticsPlayerController::ShowUnitRange(EUnitRange UnitRange)
 626→{
 627→    if (!SelectedUnit || !GridManager) return;
 628→
 629→    GridManager->ClearAllHighlights();
 630→    CacheRangeTiles.Empty();
 631→    MovementRangeTiles.Empty();
 632→
 633→    switch (UnitRange)
 634→    {
 635→    case EUnitRange::UR_Default:
 636→        break;
 637→    case EUnitRange::UR_Move:
