1005→void ALFPTacticsPlayerController::OnDeploymentPhaseStarted()
1006→{
1007→    bIsInDeployment = true;
1008→    bIsPlacingUnit = false;
1009→    PlacingPartyIndex = -1;
1010→    PlacingUnitPreview = nullptr;
1011→
1012→    // 获取玩家出生点并高亮
1013→    if (GridManager)
1014→    {
1015→        PlayerSpawnTiles = GridManager->GetSpawnPoints(ELFPSpawnFaction::SF_Player);
1016→        // 高亮显示出生点
1017→        GridManager->ShowRangeHighlight(PlayerSpawnTiles, EUnitRange::UR_Move);
1018→    }
1019→
1020→    // 获取队伍数据
1021→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1022→    if (!GI) return;
1023→
1024→    // 初始化已布置单位数组（与 PartyUnits 等长，初始全为 nullptr）
1025→    DeployedUnits.Empty();
1026→    DeployedUnits.SetNum(GI->PartyUnits.Num());
1027→
1028→    // 创建布置 UI
1029→    if (DeploymentWidgetClass && !DeploymentWidget)
1030→    {
1031→        DeploymentWidget = CreateWidget<ULFPDeploymentWidget>(this, DeploymentWidgetClass);
1032→    }
1033→
1034→    if (DeploymentWidget)
1035→    {
1036→        DeploymentWidget->Setup(GI->PartyUnits, GI->UnitRegistry);
1037→        DeploymentWidget->OnUnitSelected.AddDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1038→        DeploymentWidget->OnConfirmPressed.AddDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1039→        DeploymentWidget->AddToViewport();
1040→    }
1041→
1042→    UE_LOG(LogTemp, Log, TEXT("布置阶段：%d 个出生点，%d 个队伍单位"),
1043→        PlayerSpawnTiles.Num(), GI->PartyUnits.Num());
1044→}
