129→ALFPHexTile* ALFPAIController::FindBestMovementTile(ALFPTacticsUnit* Target) const
130→{
131→    if (!ControlledUnit || !Target || !GridManager) return nullptr;
132→
133→    // 获取所有可移动位置
134→    TArray<ALFPHexTile*> MovementRange = GridManager->GetTilesInRange(ControlledUnit->GetCurrentTile(), ControlledUnit->GetCurrentMovePoints());
135→
136→    ALFPHexTile* BestTile = nullptr;
137→    float BestPositionValue = -MAX_FLT;
138→
139→    for (ALFPHexTile* Tile : MovementRange)
140→    {
141→        // 跳过有单位的格子
142→        if (Tile->GetUnitOnTile()) continue;
143→
144→        float PositionValue = CalculatePositionValue(Tile, Target);
145→        if (PositionValue > BestPositionValue)
146→        {
147→            BestPositionValue = PositionValue;
148→            BestTile = Tile;
149→        }
150→    }
151→
152→    return BestTile;
153→}
