229→// ==== 规划阶段方法 ====
230→
231→FEnemyActionPlan ALFPAIController::CreateActionPlan(ULFPSkillBase* PreAllocatedSkill)
232→{
233→    FEnemyActionPlan Plan;
234→    Plan.EnemyUnit = ControlledUnit;
235→
236→    if (!ControlledUnit || !GridManager)
237→    {
238→        return Plan;
239→    }
240→
241→    // 1. 选择技能：优先使用预分配的，否则自行选择（会 fallback 到默认攻击）
242→    ULFPSkillBase* ChosenSkill = PreAllocatedSkill ? PreAllocatedSkill : SelectBestSkill();
243→    if (!ChosenSkill)
244→    {
245→        return Plan;
246→    }
247→    Plan.PlannedSkill = ChosenSkill;
248→
249→    // 2. 根据技能的仇恨值选择目标
250→    ALFPTacticsUnit* Target = FindBestSkillTarget(ChosenSkill);
251→    if (!Target)
252→    {
253→        return Plan;
254→    }
255→    Plan.TargetUnit = Target;
256→
257→    // 3. 目标格子 = 目标单位当前所在格子
258→    ALFPHexTile* TargetTile = Target->GetCurrentTile();
259→    if (!TargetTile)
260→    {
261→        return Plan;
262→    }
263→    Plan.TargetTile = TargetTile;
264→
265→    // 4. 寻找最佳施法站位
266→    ALFPHexTile* CasterPos = FindBestCasterPosition(ChosenSkill, TargetTile);
267→    if (!CasterPos)
268→    {
269→        // 找不到合适的施法位置，尝试原地
270→        CasterPos = ControlledUnit->GetCurrentTile();
271→    }
272→    Plan.CasterPositionTile = CasterPos;
273→
274→    // 5. 移动到施法位置
275→    if (CasterPos && CasterPos != ControlledUnit->GetCurrentTile())
276→    {
277→        ControlledUnit->MoveToTile(CasterPos);
278→    }
279→
280→    // 6. 计算技能生效范围（EffectRangeCoords 相对于目标格子偏移）
281→    FLFPHexCoordinates TargetCoords = TargetTile->GetCoordinates();
282→    for (const FLFPHexCoordinates& Offset : ChosenSkill->EffectRangeCoords)
283→    {
284→        FLFPHexCoordinates AbsCoord(
285→            TargetCoords.Q + Offset.Q,
286→            TargetCoords.R + Offset.R
287→        );
288→        if (ALFPHexTile* EffectTile = GridManager->GetTileAtCoordinates(AbsCoord))
289→        {
290→            Plan.EffectAreaTiles.Add(EffectTile);
291→        }
292→    }
293→
294→    // 如果没有定义 EffectRangeCoords，至少包含目标格子本身
295→    if (Plan.EffectAreaTiles.Num() == 0)
296→    {
297→        Plan.EffectAreaTiles.Add(TargetTile);
298→    }
299→
300→    Plan.bIsValid = true;
301→    return Plan;
302→}
303→
304→ULFPSkillBase* ALFPAIController::SelectBestSkill()
305→{
306→    if (!ControlledUnit) return nullptr;
307→
308→    TArray<ULFPSkillBase*> Skills = ControlledUnit->GetAvailableSkills();
309→    ULFPSkillBase* BestSkill = nullptr;
310→    float BestScore = -MAX_FLT;
311→
312→    for (ULFPSkillBase* Skill : Skills)
313→    {
314→        if (!Skill) continue;
315→
316→        // 轻量检查：冷却和行动点
317→        if (!Skill->IsAvailable()) continue;
318→
319→        // 找该技能的最佳目标
320→        ALFPTacticsUnit* PotentialTarget = FindBestSkillTarget(Skill);
321→        if (!PotentialTarget) continue;
322→
323→        // 检查是否存在可达的施法位置
324→        ALFPHexTile* PotentialTargetTile = PotentialTarget->GetCurrentTile();
325→        if (!PotentialTargetTile) continue;
326→
327→        ALFPHexTile* CasterPos = FindBestCasterPosition(Skill, PotentialTargetTile);
328→        if (!CasterPos) continue;
329→
330→        // 评分：仇恨值作为基础分
331→        float Score = Skill->CalculateHatredValue(ControlledUnit, PotentialTarget);
332→
333→        // 非默认攻击技能额外加分（鼓励使用特殊技能）
334→        if (!Skill->bIsDefaultAttack)
335→        {
336→            Score *= 1.5f;
337→        }
338→
339→        if (Score > BestScore)
340→        {
341→            BestScore = Score;
342→            BestSkill = Skill;
343→        }
344→    }
345→
346→    // Fallback 到默认攻击
347→    if (!BestSkill)
348→    {
349→        BestSkill = ControlledUnit->GetDefaultAttackSkill();
350→    }
351→
352→    return BestSkill;
353→}
354→
355→ALFPHexTile* ALFPAIController::FindBestCasterPosition(ULFPSkillBase* Skill, ALFPHexTile* TargetTile)
356→{
357→    if (!ControlledUnit || !Skill || !TargetTile || !GridManager) return nullptr;
358→
359→    // 获取移动范围内的所有格子
360→    ALFPHexTile* CurrentTile = ControlledUnit->GetCurrentTile();
361→    TArray<ALFPHexTile*> MovementRange = GridManager->GetTilesInRange(
362→        CurrentTile,
363→        ControlledUnit->GetCurrentMovePoints()
364→    );
365→
366→    // 也包含当前格子（可能不需要移动）
367→    MovementRange.AddUnique(CurrentTile);
368→
369→    ALFPHexTile* BestTile = nullptr;
370→    float BestValue = -MAX_FLT;
371→
372→    for (ALFPHexTile* Tile : MovementRange)
373→    {
374→        if (!Tile) continue;
375→
376→        // 跳过被其他单位占据的格子（但允许自己当前所在格）
377→        ALFPTacticsUnit* Occupant = Tile->GetUnitOnTile();
378→        if (Occupant && Occupant != ControlledUnit) continue;
379→
380→        // 位置检查：从该格子能否对目标格子释放技能
381→        if (!Skill->CanReleaseFrom(Tile, TargetTile)) continue;
382→
383→        // 评估位置价值
384→        float Value = 0.0f;
385→
386→        int32 DistToTarget = FLFPHexCoordinates::Distance(
387→            Tile->GetCoordinates(),
388→            TargetTile->GetCoordinates()
389→        );
390→
391→        // 在技能范围内加分
392→        Value += 30.0f;
393→
394→        // 离目标越近越好（在范围内的前提下）
395→        //Value += 10.0f / FMath::Max(DistToTarget, 1);
396→
397→        // 离当前位置越近越好（减少移动消耗）
398→        int32 MoveDistance = FLFPHexCoordinates::Distance(
399→            CurrentTile->GetCoordinates(),
400→            Tile->GetCoordinates()
401→        );
402→        Value -= MoveDistance * 2.0f;
403→
404→        if (Value > BestValue)
405→        {
406→            BestValue = Value;
407→            BestTile = Tile;
408→        }
409→    }
410→
411→    return BestTile;
412→}
