242→
243→	if (!IsPartyFull())
244→	{
245→		PartyUnits.Add(Unit);
246→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入出战队伍（%d/%d）"), *Unit.TypeID.ToString(), PartyUnits.Num(), MaxPartySize);
247→		return true;
248→	}
249→	if (!IsReserveFull())
