 26→void ALFPTurnManager::StartGame()
 27→{
 28→    // 收集场上所有单位（敌方预放置在关卡中）
 29→    TArray<AActor*> FoundActors;
 30→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 31→
 32→    for (AActor* Actor : FoundActors)
 33→    {
 34→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 35→        {
 36→            // 仅注册非玩家单位（玩家单位在布置阶段结束后注册）
 37→            if (Unit->GetAffiliation() != EUnitAffiliation::UA_Player)
 38→            {
 39→                TurnOrderUnits.Add(Unit);
 40→            }
 41→        }
 42→    }
 43→
 44→    // 初始化阵营 AP
 45→    FactionCurrentAP.Add(EUnitAffiliation::UA_Player, FactionInitialAP);
 46→    FactionCurrentAP.Add(EUnitAffiliation::UA_Enemy, FactionInitialAP);
 47→    FactionCurrentAP.Add(EUnitAffiliation::UA_Neutral, FactionInitialAP);
 48→
 49→    // 标记为布置阶段（不广播，等 PlayerController 绑定委托后主动调用）
 50→    CurrentPhase = EBattlePhase::BP_Deployment;
 51→}
