532→// ==== 全局技能分配 ====
533→
534→void ALFPTurnManager::AllocateEnemySkills()
535→{
536→    AllocatedSkills.Empty();
537→
538→    // 收集所有敌方单位的所有消耗AP的技能候选
539→    struct FSkillCandidate
540→    {
541→        ALFPTacticsUnit* Unit;
542→        ULFPSkillBase* Skill;
543→        float EffectivePriority;
544→    };
545→    TArray<FSkillCandidate> Candidates;
546→
547→    for (ALFPTacticsUnit* Enemy : PlanningOrderEnemies)
548→    {
549→        if (!Enemy || !Enemy->IsAlive()) continue;
550→
551→        TArray<ULFPSkillBase*> Skills = Enemy->GetAvailableSkills();
552→        for (ULFPSkillBase* Skill : Skills)
553→        {
554→            if (!Skill) continue;
555→            if (Skill->ActionPointCost <= 0) continue; // 0消耗技能不参与竞争
556→            if (Skill->CurrentCooldown > 0) continue;  // 冷却中跳过
557→
558→            FSkillCandidate Candidate;
559→            Candidate.Unit = Enemy;
560→            Candidate.Skill = Skill;
561→            Candidate.EffectivePriority = Skill->GetEffectivePriority();
562→            Candidates.Add(Candidate);
563→        }
564→    }
565→
566→    // 按有效优先级降序排序
567→    Candidates.Sort([](const FSkillCandidate& A, const FSkillCandidate& B) {
568→        return A.EffectivePriority > B.EffectivePriority;
569→    });
570→
571→    // 依次分配：如果阵营AP足够且该单位尚未分配
572→    for (const FSkillCandidate& Candidate : Candidates)
573→    {
574→        // 该单位已分配过技能，跳过
575→        if (AllocatedSkills.Contains(Candidate.Unit)) continue;
576→
577→        // 检查阵营AP是否足够
578→        if (HasEnoughFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost))
579→        {
580→            AllocatedSkills.Add(Candidate.Unit, Candidate.Skill);
581→            ConsumeFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost);
582→        }
583→    }
584→
585→    // 未分配到AP技能的敌人会在 CreateActionPlan 中 fallback 到默认攻击
586→}
