588→void ALFPTurnManager::CheckBattleEnd()
589→{
590→    if (bBattleEnded) return;
591→    if (CurrentPhase == EBattlePhase::BP_Deployment) return;
592→
593→    bool bHasPlayerUnit = false;
594→    bool bHasEnemyUnit = false;
595→
596→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
597→    {
598→        if (!Unit || !Unit->IsAlive()) continue;
599→
600→        if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player)
601→            bHasPlayerUnit = true;
602→        else if (Unit->GetAffiliation() == EUnitAffiliation::UA_Enemy)
603→            bHasEnemyUnit = true;
604→    }
605→
606→    if (!bHasEnemyUnit)
607→    {
608→        // 胜利：所有敌方单位消灭
609→        bBattleEnded = true;
610→        UE_LOG(LogTemp, Log, TEXT("战斗结束: 胜利！"));
611→        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
612→        {
613→            GM->EndBattle(true);
614→        }
615→    }
616→    else if (!bHasPlayerUnit)
617→    {
618→        // 失败：所有玩家单位消灭
619→        bBattleEnded = true;
620→        UE_LOG(LogTemp, Log, TEXT("战斗结束: 败北"));
621→        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
622→        {
623→            GM->EndBattle(false);
624→        }
625→    }
626→}
