    // 阵营颜色
    UFUNCTION(BlueprintPure, Category = "Unit Display")
    FLinearColor GetAffiliationColor() const;

    void UpdateHealthUI();

protected:
    // 处理死亡
    void HandleDeath();

    // 攻击范围
    UPROPERTY(EditAnywhere, Category = "Unit Combat")
    int32 AttackRange = 2;

    // 近战攻击模式
    UPROPERTY(EditAnywhere, Category = "Unit Combat")
