    // 计算施法格子到目标格子的距离
    int32 Dist = FLFPHexCoordinates::Distance(
        CasterTile->GetCoordinates(),
        TargetTile->GetCoordinates()
    );

    // 检查是否在技能释放范围内
    if (Dist < Range.MinRange || Dist > Range.MaxRange) return false;

    // TODO: 视线检查 (bRequireLineOfSight)

    return true;
}

